// context
typedef struct { char name[64]; int status; int priority; } Item;

void setup_item(Item* it, const char* name, int prio) {
    strncpy(it->name, name, sizeof(it->name) - 1);
    it->name[sizeof(it->name) - 1] = '\0';
    it->status = 1;
    it->priority = prio;
}

// target function
void process_item(const char* name, int prio) {
    Item* item = (Item*)malloc(sizeof(Item));
    setup_item(item, name, prio);
    free(item);
    printf("item: %s prio=%d\n", item->name, item->priority);
}

// context
typedef struct { char host[128]; int fd; int port; } Conn;

int bind_socket(Conn* c, int port) {
    c->fd = port % 1024 + 1;
    c->port = port;
    return c->fd > 0;
}

// target function
int open_conn(const char* host, int port) {
    Conn* c = (Conn*)malloc(sizeof(Conn));
    strncpy(c->host, host, sizeof(c->host) - 1);
    c->host[sizeof(c->host) - 1] = '\0';
    bind_socket(c, port);
    free(c);
    printf("connected %s:%d fd=%d\n", c->host, c->port, c->fd);
    return c->fd;
}

// context
typedef struct { char level[32]; char msg[128]; int seq; } LogEntry;

void write_log(LogEntry* e) {
    fprintf(stderr, "[%s] %s\n", e->level, e->msg);
}

// target function
int log_event(const char* level, const char* msg) {
    LogEntry* e = (LogEntry*)malloc(sizeof(LogEntry));
    strncpy(e->level, level, sizeof(e->level) - 1);
    e->level[sizeof(e->level) - 1] = '\0';
    strncpy(e->msg, msg, sizeof(e->msg) - 1);
    e->msg[sizeof(e->msg) - 1] = '\0';
    e->seq = 0;
    free(e);
    write_log(e);
    return 0;
}

// context
typedef struct { int id; char label[32]; double score; } Record;

double compute_score(Record* r) {
    return r->id * 1.5;
}

// target function
double score_entry(int id, const char* label) {
    Record* r = (Record*)malloc(sizeof(Record));
    r->id = id;
    strncpy(r->label, label, sizeof(r->label) - 1);
    r->label[sizeof(r->label) - 1] = '\0';
    r->score = compute_score(r);
    free(r);
    return r->score;
}
